{
    "code": "ct_releves",
    "description": "Table des relevés",
    "disabled": false,
    "name": "ct_releves",
    "storeInES": false,
    "storeAsTable": true,
    "field": [
        {
            "code": "id_releve",
            "description": "Identifiant de la relève",
            "fieldType": "LONG"
        },
        {
            "code": "num_compteur",
            "description": "Numéro du compteur",
            "fieldType": "STRING"
        },
        {
            "code": "num_contrat",
            "description": "Nom du contrat",
            "fieldType": "STRING"
        },
         {
            "code": "nom_client",
            "description": "Nom du client",
            "fieldType": "STRING"
        },
        {
            "code": "date_releve",
            "description": "Date de la relève",
            "fieldType": "DATE"
        },
        {
            "code": "nature_releve",
            "description": "Nature de la relève",
            "fieldType": "LIST",
            "listValues": {
                "REEL": "REEL",
                "ESTIME": "ESTIME",
                "EVENEMENT": "EVENEMENT",
                "DEPOSE": "DEPOSE",
                "POSE": "POSE"
            }
        },
        {
            "code": "origine",
            "description": "Origine de la relève",
            "fieldType": "LIST",
            "listValues": {
                "MAREL": "MAREL",
                "SATURNE": "SATURNE",
                "SMARTSIDE": "SMARTSIDE",
                "ENERLAKE": "ENERLAKE",
                "ADVANCE": "ADVANCE",
                "DI": "DI",
                "AEL": "AEL",
                "TELEPHONE": "TELEPHONE",
                "MANUEL": "MANUEL"
            }
        },
        {
            "code": "id_pds",
            "description": "Identifiant du point de service",
            "fieldType": "STRING"
        },
        {
            "code": "code_releve",
            "description": "Code de la relève",
            "fieldType": "STRING"
        },
        {
            "code": "code_observation",
            "description": "Code observation",
            "fieldType": "STRING"
        },
        {
            "code": "code_rfe",
            "description": "Code RFE",
            "fieldType": "STRING"
        },
        {
            "code": "lot",
            "description": "Lot",
            "fieldType": "LONG"
        },
        {
            "code": "tournee",
            "description": "Tournée",
            "fieldType": "LONG"
        },
        {
            "code": "exploitation",
            "description": "Exploitation",
            "fieldType": "STRING"
        },
        {
            "code": "poste_horosaisonnier",
            "description": "Poste horosaisonnier",
            "fieldType": "LIST",
            "listValues": {
                "BASE": "BASE",
                "HP": "HP",
                "HC": "HC",
                "JOUR": "JOUR",
                "NUIT": "NUIT"
            }
        },
        {
            "code": "nature_mesure",
            "description": "Nature de la mesure",
            "fieldType": "LIST",
            "listValues": {
                "EA": "EA",
                "ER": "ER",
                "EAi": "EAi",
                "ERi": "ERi",
                "Imax": "Imax",
                "PA": "PA",
                "DD": "DD",
                "VOL": "VOL",
                "VOLR": "VOLR"
            }
        },
        {
            "code": "mesure",
            "description": "Mesure",
            "fieldType": "STRING"
        },
        {
            "code": "unite",
            "description": "Unite",
            "fieldType": "LIST",
            "listValues": {
                "kVA": "kVA",
                "kW": "kW",
                "h": "h",
                "min": "min",
                "m3": "m3",
                "L": "L",
                "A": "A"
            }
        },
        {
            "code": "code_erreur",
            "description": "Code de l'erreur",
            "fieldType": "STRING"
        },
        {
            "code": "message_erreur",
            "description": "Message de l'erreur",
            "fieldType": "STRING",
            "maxValue": 200
        },
        {
            "code": "statut_releve",
            "description": "Statut",
            "fieldType": "LIST",
            "listValues": {
                "VALIDE": "VALIDE",
                "CALCULE": "CALCULE",
                "ERREUR": "ERREUR"
            }
        }
    ],
    "action": []
}
